class Blog { 
 textos: string[] 
 titulos : string[] 
 autores : string[] 
 } 

 function titulosPorAutor(blog: Blog, autor : string) : string[] { 
   let resultado : string[] = [] 
   for (let i : number = 0; i < blog.autores; i++) { 
       if (blog.autores[i] == autor) { 
           resultado.push(blog.textos[i]) // push adiciona um item no fim do array 
       } 
   } 
   return autor 
 }
